import React, { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ChevronLeft, ChevronRight, Quote, Star } from "lucide-react";
import { testimonials as rawTestimonialsData } from "@/data";

interface Testimonial {
  id: number | string;
  message: string;
  name: string;
  rating: number;
  image: string;
  title?: string;
}

const testimonialsData: Testimonial[] = rawTestimonialsData.map((t, i) => ({
  ...t,
  id: t.id ?? i,
}));

const renderStars = (count: number) => {
  const stars = [];
  const clamped = Math.max(0, Math.min(5, count));
  for (let i = 0; i < 5; i++) {
    stars.push(
      <Star
        key={i}
        className={`h-6 w-6 transition-colors ${
          i < clamped
            ? "text-yellow-400 fill-current"
            : "text-gray-300 dark:text-gray-600"
        }`}
        aria-hidden="true"
      />
    );
  }
  return stars;
};

const TestimonialsSection: React.FC = () => {
  const [current, setCurrent] = useState(0);
  const [dir, setDir] = useState(0);

  if (!testimonialsData.length) return null;

  useEffect(() => {
    const timer = setInterval(() => {
      setDir(1);
      setCurrent((c) => (c + 1) % testimonialsData.length);
    }, 7000);
    return () => clearInterval(timer);
  }, []);

  const handlePrev = () => {
    setDir(-1);
    setCurrent((c) => (c === 0 ? testimonialsData.length - 1 : c - 1));
  };
  const handleNext = () => {
    setDir(1);
    setCurrent((c) => (c + 1) % testimonialsData.length);
  };
  const handleDot = (i: number) => {
    if (i === current) return;
    setDir(i > current ? 1 : -1);
    setCurrent(i);
  };

  const variants = {
    enter: (d: number) => ({ opacity: 0, x: d > 0 ? 100 : -100, scale: 0.98 }),
    center: {
      opacity: 1,
      x: 0,
      scale: 1,
      transition: {
        x: { type: "spring", stiffness: 300, damping: 30 },
        opacity: { duration: 0.4 },
        scale: { duration: 0.4 },
      },
    },
    exit: (d: number) => ({
      opacity: 0,
      x: d < 0 ? 100 : -100,
      scale: 0.98,
      transition: {
        x: { type: "spring", stiffness: 300, damping: 30 },
        opacity: { duration: 0.4 },
        scale: { duration: 0.4 },
      },
    }),
  };

  const data = testimonialsData[current];

  return (
    <section className="relative bg-gradient-to-br from-blue-50 to-purple-50 dark:from-gray-900 dark:to-gray-800 py-16 overflow-hidden">
      <div className="container mx-auto px-4 max-w-4xl text-center">
        <h2 className="mb-12">
          <span className="inline-block bg-gradient-to-r from-orange-600 to-red-800 text-white font-bold px-6 py-2 rounded-full shadow-lg">
            Clients Voice
          </span>
        </h2>

        <div className="relative">
          <AnimatePresence initial={false} custom={dir} mode="wait">
            <motion.div
              key={data.id}
              custom={dir}
              variants={variants}
              initial="enter"
              animate="center"
              exit="exit"
              className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-3xl p-8 md:p-10 shadow-lg hover:shadow-xl transition-shadow duration-300 relative"
            >
              <Quote className="absolute top-4 md:top-8 left-4 md:left-8 w-12 h-12 md:w-16 md:h-16 text-black dark:text-white opacity-10 dark:opacity-[0.08] transform -rotate-12 pointer-events-none" aria-hidden="true" />
              <Quote className="absolute bottom-4 md:bottom-8 right-4 md:right-8 w-12 h-12 md:w-16 md:h-16 text-black dark:text-white opacity-10 dark:opacity-[0.08] transform rotate-180 pointer-events-none" aria-hidden="true" />


              {/* Enlarged Avatar */}
              <div className="mb-6 flex justify-center">
                <img
                  src={data.image}
                  alt={data.name}
                  className="w-48 h-48 rounded-full ring-4 ring-gray-200 dark:ring-gray-800 object-cover"
                  loading="lazy"
                />
              </div>

              {/* Quote Text */}
              <p className="font-serif text-sm md:text-base italic leading-relaxed text-gray-700 dark:text-gray-300 px-4">
                {data.message}
              </p>

              {/* Name */}
              <h3 className="mt-6 font-rubik font-semibold text-lg text-gray-900 dark:text-white">
                {data.name}
              </h3>
              {data.title && (
                <p className="font-sans text-sm text-gray-500 dark:text-gray-400 mt-1">
                  {data.title}
                </p>
              )}

              {/* Rating Below Name */}
              <div className="mt-4 flex justify-center space-x-1">
                {renderStars(data.rating)}
              </div>
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Navigation Arrows */}
        <button
          onClick={handlePrev}
          className="absolute left-0 top-1/2 -translate-y-1/2 bg-white/90 dark:bg-gray-700/90 rounded-full p-3 shadow-lg hover:scale-105 transition"
          aria-label="Previous"
        >
          <ChevronLeft className="w-6 h-6 text-gray-700 dark:text-gray-200" />
        </button>
        <button
          onClick={handleNext}
          className="absolute right-0 top-1/2 -translate-y-1/2 bg-white/90 dark:bg-gray-700/90 rounded-full p-3 shadow-lg hover:scale-105 transition"
          aria-label="Next"
        >
          <ChevronRight className="w-6 h-6 text-gray-700 dark:text-gray-200" />
        </button>

        {/* Pagination Dots */}
        <div className="flex justify-center mt-8 space-x-2">
          {testimonialsData.map((_, i) => (
            <button
              key={i}
              onClick={() => handleDot(i)}
              className={`w-3 h-3 rounded-full transition ${
                i === current
                  ? "bg-red-600 dark:bg-blue-500 scale-125"
                  : "bg-gray-300 dark:bg-gray-600 hover:bg-gray-400 dark:hover:bg-gray-500"
              }`}
              aria-label={`Go to testimonial ${i + 1}`}
            />
          ))}
        </div>
      </div>
    </section>
  );
};

export default TestimonialsSection;

// src/components/Chatbot.tsx
import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Resizable } from 're-resizable';
import {
  MessageSquare,
  Send,
  X,
  Loader2,
  Sparkles,
  ChevronDown,
  ChevronDownCircleIcon,
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { generateResponse } from '@/lib/openai';
import pdfContent from '@/assets/sample.pdf?raw';
import Logo from '@/assets/logo(3).png';

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

const Chatbot: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([
    'What is new about Infrastructure?',
    'Tell me about Millenium Solutions',
    'Tell me about your team structure',
    "What's included in maintenance plans?",
  ]);
  const [isFullscreen, setFullscreen] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const welcomeMessage =
    "👋 Hi there! I'm Millenium Solutions AI assistant. I can help you with information about our software development services and pricing. Feel free to ask any questions!";

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      setMessages([{ role: 'assistant', content: welcomeMessage }]);
    }
  }, [isOpen, messages.length]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  const handleSuggestionClick = async (text: string) => {
    setInput(text);
    await handleSubmit({ preventDefault: () => {} } as any);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages((prev) => [...prev, { role: 'user', content: userMsg }]);
    setIsLoading(true);

    try {
      const context = messages.filter((_, i) => i !== 0);
      const resp = await generateResponse(
        [...context, { role: 'user', content: userMsg }],
        pdfContent
      );
      setMessages((prev) => [...prev, { role: 'assistant', content: resp.answer }]);
      setSuggestions(resp.suggestions);
    } catch {
      setMessages((prev) => [
        ...prev,
        { role: 'assistant', content: 'I encountered a problem, Please try again.' },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit(e as any);
    }
  };

  return (
    <>
      {/* Chat Toggle Button */}
      <motion.button
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setIsOpen((open) => !open)}
        className="fixed bottom-6 right-6 z-50 bg-green-500 hover:bg-green-600 text-white p-4 rounded-full shadow-lg transition-all duration-300"
      >
        <MessageSquare className="h-6 w-6" />
      </motion.button>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <Resizable
            defaultSize={{ width: 400, height: 600 }}
            minWidth={280}
            minHeight={240}
            maxWidth="90vw"
            maxHeight="90vh"
            enable={{
              top: false,
              right: false,
              bottom: false,
              left: false,
              topRight: false,
              bottomRight: true,
              bottomLeft: false,
              topLeft: false,
            }}
            handleStyles={{
              bottomRight: {
                width: 16,
                height: 16,
                background: 'rgba(0,0,0,0.2)',
                borderRadius: '4px',
                right: 8,
                bottom: 8,
                cursor: 'se-resize',
              },
            }}
            style={isFullscreen ? {
              position: 'fixed', top: 0, left: 0, width: '100vw', height: '100vh',
              zIndex: 50, resize: 'none'
            } : { position: 'fixed', bottom: 96, right: 24, zIndex: 50 }}
          >
            <motion.div
              initial={{ opacity: 0, y: 20, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              exit={{ opacity: 0, y: 20, scale: 0.95 }}
              transition={{ duration: 0.2 }}
              className="w-full h-full flex flex-col bg-white dark:bg-gray-800 rounded-xl shadow-2xl border border-gray-200 dark:border-gray-700 overflow-hidden"
            >
              {/* Header */}
              <div className="p-3 bg-gradient-to-r from-red-600 to-red-600 text-gray-700 flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <div className="bg-white/20 p-2 rounded-full">
                    <img src={Logo} alt="Millenium Logo" className="h-8 w-8 rounded-full" />
                  </div>
                  <div>
                    <h3 className="font-bold text-sm">Millenium Solutions AI Agent</h3>
                    <p className="font-semibold text-xs text-white/80">Expert in IT Consultancy.</p>
                  </div>
                </div>
                <div className="flex items-center space-x-2">
                  <button onClick={() => setFullscreen((f) => !f)} className="hover:bg-white/20 p-2 rounded-lg">
                    <ChevronDown className={`h-5 w-5 transform ${isFullscreen ? 'rotate-180' : 'rotate-90'}`} />
                  </button>
                  <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-2 rounded-lg">
                    <X className="h-5 w-5" />
                  </button>
                </div>
              </div>

              {/* Messages */}
              <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 dark:bg-gray-900">
                {messages.map((msg, i) => (
                  <motion.div
                    key={i}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.2 }}
                    className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                  >
                    {msg.role === 'assistant' && (
                      <div className="w-7 h-7 rounded-full bg-blue-600 flex items-center justify-center mr-2">
                        <Sparkles className="h-4 w-4 text-white" />
                      </div>
                    )}
                    <div
                      className={`max-w-[80%] p-3 rounded-2xl ${
                        msg.role === 'user'
                          ? 'bg-blue-600 text-white rounded-br-none'
                          : 'bg-white dark:bg-gray-800 text-gray-900 dark:text-white shadow-md rounded-bl-none'
                      }`}
                    >
                      <ReactMarkdown className="prose dark:prose-invert max-w-none text-sm">
                        {msg.content}
                      </ReactMarkdown>
                    </div>
                  </motion.div>
                ))}

                {isLoading && (
                  <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="flex items-center space-x-2">
                    <div className="w-7 h-7 rounded-full bg-blue-600 flex items-center justify-center">
                      <Loader2 className="h-4 w-4 text-white animate-spin" />
                    </div>
                    <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl shadow-md">
                      <div className="flex space-x-2">
                        <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                        <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '200ms' }} />
                        <div className="w-2 h-2 bg-blue-600 rounded-full animate-bounce" style={{ animationDelay: '400ms' }} />
                      </div>
                    </div>
                  </motion.div>
                )}
                <div ref={messagesEndRef} />
              </div>

              {/* Suggestions */}
              <div className="p-3 bg-white dark:bg-gray-800 border-t dark:border-gray-700">
                <p className="text-xs text-gray-500 dark:text-gray-400 mb-2">
                  {messages.length === 1
                    ? 'Suggested questions:'
                    : 'Take a look at the suggested questions to explore more:'}
                </p>
                <div className="flex flex-wrap gap-2 max-h-24 overflow-y-auto relative">
                  {suggestions.map((s, idx) => (
                    <button
                      key={idx}
                      onClick={() => handleSuggestionClick(s)}
                      className="text-xs bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 px-3 py-1 rounded-full hover:bg-gray-200 dark:hover:bg-gray-600 transition-colors duration-200"
                    >
                      {s}
                    </button>
                  ))}
                  <motion.div animate={{ y: [0, 5, 0] }} transition={{ duration: 1.5, repeat: Infinity }} className="absolute bottom-1 inset-x-0 flex justify-center">
                    <ChevronDownCircleIcon className="h-7 w-7 text-red-500 dark:text-red-400" />
                  </motion.div>
                </div>
              </div>

              {/* Input */}
              <form onSubmit={handleSubmit} className="p-3 bg-white dark:bg-gray-800 border-t dark:border-gray-700">
                <div className="flex space-x-2">
                  <textarea
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    onKeyDown={handleKeyDown}
                    placeholder="Ask About Millenium Solutions..."
                    rows={1}
                    className="flex-1 p-2 border border-gray-200 dark:border-gray-600 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 dark:bg-gray-700 dark:text-white resize-none placeholder-gray-400 dark:placeholder-gray-500 text-sm"
                  />
                  <button
                    type="submit"
                    disabled={isLoading || !input.trim()}
                    className="bg-gradient-to-r from-blue-600 to-blue-700 text-white p-2 rounded-xl hover:from-blue-700 hover:to-blue-800 transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    <Send className="h-5 w-5" />
                  </button>
                </div>
              </form>
            </motion.div>
          </Resizable>
        )}
      </AnimatePresence>
    </>
  );
};

export default Chatbot;

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "dark" | "light" | "system";

type ThemeProviderProps = {
  children: React.ReactNode;
  defaultTheme?: Theme;
  storageKey?: string;
};

type ThemeProviderState = {
  theme: Theme;
  setTheme: (theme: Theme) => void;
};

const initialState: ThemeProviderState = {
  theme: "system",
  setTheme: () => null,
};

const ThemeProviderContext = createContext<ThemeProviderState>(initialState);

export function ThemeProvider({
  children,
  defaultTheme = "system",
  storageKey = "opus-ui-theme",
  ...props
}: ThemeProviderProps) {
  const [theme, setTheme] = useState<Theme>(
    () => (localStorage.getItem(storageKey) as Theme) || defaultTheme
  );

  useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove("light", "dark");

    if (theme === "system") {
      const systemTheme = window.matchMedia("(prefers-color-scheme: dark)")
        .matches
        ? "dark"
        : "light";
      root.classList.add(systemTheme);
      return;
    }

    root.classList.add(theme);
  }, [theme]);

  const value = {
    theme,
    setTheme: (theme: Theme) => {
      localStorage.setItem(storageKey, theme);
      setTheme(theme);
    },
  };

  return (
    <ThemeProviderContext.Provider {...props} value={value}>
      {children}
    </ThemeProviderContext.Provider>
  );
}

export const useTheme = () => {
  const context = useContext(ThemeProviderContext);

  if (context === undefined)
    throw new Error("useTheme must be used within a ThemeProvider");

  return context;
};

