// Reusable Counter component with IntersectionObserver (No changes needed)
const Counter: React.FC<{ target: number; suffix?: string; duration?: number }> = ({
  target,
  suffix = "",
  duration = 2000,
}) => {
  const [count, setCount] = useState(0);
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => setIsVisible(entry.isIntersecting),
      { threshold: 0.5 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => {
      if (ref.current) observer.unobserve(ref.current);
    };
  }, []);

  useEffect(() => {
    if (!isVisible || target <= 0) {
        setCount(0);
        return;
    }

    const startTime = performance.now();
    const updateCount = (currentTime: number) => {
      const elapsedTime = currentTime - startTime;
      const progress = Math.min(elapsedTime / duration, 1);
      const currentCount = Math.floor(progress * target);

      setCount(isFinite(currentCount) ? currentCount : target); // Check for Infinity

      if (progress < 1) {
        requestAnimationFrame(updateCount);
      } else {
        setCount(target);
      }
    };

    const animationFrameId = requestAnimationFrame(updateCount);

    return () => cancelAnimationFrame(animationFrameId);
  }, [target, duration, isVisible]);

    const displayCount = isFinite(count) ? count : 0; // Check before display

  return <span ref={ref}>{displayCount}{suffix}</span>;
};


