// --- NEW & IMPROVED: Re-triggering Counter Component ---
const Counter = ({ target, suffix = "", duration = 2000 }: { target: number; suffix?: string; duration?: number }) => {
  const [count, setCount] = useState(0);
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef<HTMLSpanElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        // This is the key change: Set visibility based on intersection status
        setIsVisible(entry.isIntersecting);
      },
      { threshold: 0.5 } 
    );
    if (ref.current) observer.observe(ref.current);
    
    return () => { if (ref.current) observer.disconnect(); };
  }, []); 

  useEffect(() => {
    if (isVisible) {
      // Start animation when it becomes visible
      let start = 0;
      const startTime = performance.now();
      const animate = (currentTime: number) => {
          const elapsedTime = currentTime - startTime;
          const progress = Math.min(elapsedTime / duration, 1);
          const currentVal = Math.floor(progress * target);
          setCount(currentVal);

          if (progress < 1) requestAnimationFrame(animate);
          else setCount(target);
      };
      requestAnimationFrame(animate);
    } else {
      // Reset count when it's not visible
      setCount(0);
    }
  }, [isVisible, target, duration]);

  return <span ref={ref}>{count.toLocaleString()}{suffix}</span>;
};

